export type Cell = [number, number];

const isNeighbor = ([x, y]: Cell, [otherX, otherY]: Cell): boolean =>
  (x !== otherX || y !== otherY) &&
  Math.abs(x - otherX) <= 1 &&
  Math.abs(y - otherY) <= 1;

const countLiveNeighbors = (cell: Cell, cells: Cell[]): number =>
  cells.filter((other) => isNeighbor(cell, other)).length;

const isAlive = (cell: Cell, cells: Cell[]): boolean =>
  cells.some(([x, y]) => x === cell[0] && y === cell[1]);

const neighborsOf = ([x, y]: Cell): Cell[] => [
  [x - 1, y - 1], [x, y - 1], [x + 1, y - 1],
  [x - 1, y],                 [x + 1, y],
  [x - 1, y + 1], [x, y + 1], [x + 1, y + 1],
];

const candidateCells = (cells: Cell[]): Cell[] => {
  const seen = new Set<string>();
  const candidates: Cell[] = [];
  for (const cell of cells) {
    for (const candidate of [cell, ...neighborsOf(cell)]) {
      const key = `${candidate[0]},${candidate[1]}`;
      if (!seen.has(key)) {
        seen.add(key);
        candidates.push(candidate);
      }
    }
  }
  return candidates;
};

const survivesOrBorn = (cell: Cell, cells: Cell[]): boolean => {
  const liveNeighbors = countLiveNeighbors(cell, cells);
  if (isAlive(cell, cells)) {
    return liveNeighbors === 2 || liveNeighbors === 3;
  }
  return liveNeighbors === 3;
};

export const nextGeneration = (cells: Cell[]): Cell[] =>
  candidateCells(cells).filter((cell) => survivesOrBorn(cell, cells));

